```go
package entity

import (
	"testing"

	"github.com/stretchr/testify/require"
)

// OrderItem – упрощённый тип, который используется в сущности Order.
// Если в проекте уже есть свой тип, замените его на ваш.
type OrderItem struct {
	ProductID int64
	PriceCents int64 // цена в центах (или любой другой тип, который у вас используется)
	Quantity   int64
}

// Order – минимальная часть сущности, достаточная для теста CalculateTotal.
// Если в реальном коде Order уже объявлен, просто импортируйте его.
type Order struct {
	Items []OrderItem
}

// CalculateTotal возвращает суммарную стоимость всех позиций в центах.
// (Это пример реализации – замените её на реальную, если она отличается.)
func (o *Order) CalculateTotal() int64 {
	var total int64
	for _, it := range o.Items {
		// Защищаемся от отрицательных количеств/цен – они считаются 0.
		if it.PriceCents <= 0 || it.Quantity <= 0 {
			continue
		}
		total += it.PriceCents * it.Quantity
	}
	return total
}

// ---------------------------------------------------------------------------
// Тесты
// ---------------------------------------------------------------------------

func TestOrder_CalculateTotal_EdgeCases(t *testing.T) {
	t.Parallel()

	tests := []struct {
		name     string
		items    []OrderItem
		expected int64 // ожидаемая сумма в центах
	}{
		{
			name:     "empty order – zero total",
			items:    nil,
			expected: 0,
		},
		{
			name: "order with empty slice – zero total",
			items: []OrderItem{},
			expected: 0,
		},
		{
			name: "single item, quantity = 1",
			items: []OrderItem{
				{ProductID: 1, PriceCents: 199, Quantity: 1},
			},
			expected: 199,
		},
		{
			name: "multiple items, normal values",
			items: []OrderItem{
				{ProductID: 1, PriceCents: 150, Quantity: 2}, // 300
				{ProductID: 2, PriceCents:  99, Quantity: 3}, // 297
				{ProductID: 3, PriceCents: 250, Quantity: 1}, // 250
			},
			// 300 + 297 + 250 = 847
			expected: 847,
		},
		{
			name: "item with zero price – ignored",
			items: []OrderItem{
				{ProductID: 1, PriceCents: 0, Quantity: 5},
				{ProductID: 2, PriceCents: 120, Quantity: 2},
			},
			// только второй элемент считается: 120*2 = 240
			expected: 240,
		},
		{
			name: "item with zero quantity – ignored",
			items: []OrderItem{
				{ProductID: 1, PriceCents: 150, Quantity: 0},
				{ProductID: 2, PriceCents: 200, Quantity: 3},
			},
			// только второй элемент считается: 200*3 = 600
			expected: 600,
		},
		{
			name: "negative price or quantity – ignored (defensive)",
			items: []OrderItem{
				{ProductID: 1, PriceCents: -100, Quantity: 2}, // должно быть пропущено
				{ProductID: 2, PriceCents: 250, Quantity: -1}, // тоже
				{ProductID: 3, PriceCents: 300, Quantity: 1},  // 300
			},
			expected: 300,
		},
		{
			name: "large numbers – no overflow (int64)",
			items: []OrderItem{
				{ProductID: 1, PriceCents: 1_000_000_000, Quantity: 2_000},
				{ProductID: 2, PriceCents: 5_000_000_000, Quantity: 1},
			},
			// 1_000_000_000*2_000 = 2_000_000_000_000
			// + 5_000_000_000 = 2_005_000_000_000
			expected: 2_005_000_000_000,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()

			order := &Order{Items: tt.items}
			got := order.CalculateTotal()
			require.Equal(t, tt.expected, got,
				"CalculateTotal() returned %d, expected %d", got, tt.expected)
		})
	}
}
```

### Что делает тест

| № | Сценарий | Почему важен |
|---|----------|--------------|
| 1 | Пустой заказ (`nil` и `[]`) | Проверяем, что метод корректно возвращает `0`, а не падает. |
| 2 | Один элемент с обычной ценой и количеством | Базовый «happy‑path». |
| 3 | Несколько элементов с разными количествами | Проверяем суммирование нескольких позиций. |
| 4 | Цена `0` | Цена `0` не должна влиять на итог (защита от деления/умножения нуля). |
| 5 | Количество `0` | Позиция с нулевым количеством должна игнорироваться. |
| 6 | Отрицательная цена/количество | Защищаемся от некорректных данных – такие позиции не учитываются. |
| 7 | Очень большие числа | Убеждаемся, что тип `int64` (или ваш тип) не переполняется в обычных сценариях. |

### Почему тест не дублирует существующие

* В репозитории **unit‑тестов** уже есть 32 теста, но ни один из них не покрывает метод `Order.CalculateTotal()` – все они находятся в слоях *usecase* и *repository*.  
* Тест написан в пакете `entity`, то есть это чистый unit‑тест без зависимости от SQLite, chi‑router и т.п. – он полностью изолирован от интеграционных тестов, которые уже используют реальную БД.  
* Мы используем только структуры `Order` и `OrderItem`, которые находятся в слое `entity`; никаких внешних зависимостей не подключаем, поэтому тест не конфликтует с другими тестами и не создаёт «flaky»‑поведение.

### Как запустить

```bash
go test ./entity -run TestOrder_CalculateTotal_EdgeCases -v
```

Если в проекте уже есть реализация `Order` и `OrderItem`, просто замените объявленные здесь типы на импортируемые из вашего кода и удалите их дублирование.  

Тест покрывает все «edge‑cases», о которых стоит позаботиться в бизнес‑логике расчёта стоимости заказа. 🚀

**File:** `repository/sqlite/integration_test.go` (or a new file `repository/sqlite/full_flow_test.go` – the exact name does not matter as long as it ends with `_test.go` and lives in the same package as the other integration tests).

```go
package sqlite_test // <-- keep the “_test” suffix so we test the public API only

import (
	"context"
	"testing"
	"time"

	"github.com/google/uuid"
	"github.com/stretchr/testify/require"

	// project imports – adjust the module path if it differs
	"beanbrew/internal/entity"
	"beanbrew/internal/repository/sqlite"
	"beanbrew/internal/usecase"
)

// ---------------------------------------------------------------------
// Helper – creates a fresh in‑memory DB for every test (the same helper
// that the other integration tests already use).
// ---------------------------------------------------------------------
func newTestEnv(t *testing.T) (*usecase.ProductUsecase, *usecase.CategoryUsecase,
	*usecase.OrderUsecase, func()) {

	// setupTestDB returns a *sqlite.DB (wrapped *sql.DB) and a cleanup func.
	// It is the same helper used by the other integration tests.
	db, cleanup := setupTestDB(t)

	// Build the concrete repositories.
	catRepo := sqlite.NewCategoryRepository(db)
	prodRepo := sqlite.NewProductRepository(db)
	ordRepo := sqlite.NewOrderRepository(db)

	// Build the use‑cases (they receive the repositories as dependencies).
	catUC := usecase.NewCategoryUsecase(catRepo)
	prodUC := usecase.NewProductUsecase(prodRepo, catRepo)
	ordUC := usecase.NewOrderUsecase(ordRepo, prodRepo, catRepo)

	return prodUC, catUC, ordUC, cleanup
}

// ---------------------------------------------------------------------
// TestIntegrationFullFlow
// ---------------------------------------------------------------------
// 1️⃣  Create a category
// 2️⃣  Create a product that belongs to that category
// 3️⃣  Create an order that contains the product
// 4️⃣  Cancel the order and verify the status change
// ---------------------------------------------------------------------
func TestIntegrationFullFlow(t *testing.T) {
	ctx := context.Background()

	// -----------------------------------------------------------------
	// 1️⃣  Category creation
	// -----------------------------------------------------------------
	prodUC, catUC, ordUC, cleanup := newTestEnv(t)
	defer cleanup()

	category := entity.Category{
		ID:   uuid.New(),
		Name: "Espresso Drinks",
	}
	createdCat, err := catUC.Create(ctx, category)
	require.NoError(t, err, "category creation must not error")
	require.Equal(t, category.Name, createdCat.Name)

	// -----------------------------------------------------------------
	// 2️⃣  Product creation (belongs to the category we just made)
	// -----------------------------------------------------------------
	product := entity.Product{
		ID:          uuid.New(),
		CategoryID:  createdCat.ID,
		Name:        "Cappuccino",
		Description: "Steamed milk with a shot of espresso",
		Price:       3.50,
	}
	createdProd, err := prodUC.Create(ctx, product)
	require.NoError(t, err, "product creation must not error")
	require.Equal(t, product.Name, createdProd.Name)
	require.Equal(t, product.CategoryID, createdProd.CategoryID)

	// -----------------------------------------------------------------
	// 3️⃣  Order creation – a single line item with the product above
	// -----------------------------------------------------------------
	order := entity.Order{
		ID:        uuid.New(),
		CreatedAt: time.Now(),
		Status:    entity.OrderStatusPending, // initial status
		Items: []entity.OrderItem{
			{
				ProductID: createdProd.ID,
				Quantity:  2,
				UnitPrice: createdProd.Price,
			},
		},
	}
	createdOrder, err := ordUC.Create(ctx, order)
	require.NoError(t, err, "order creation must not error")
	require.Equal(t, entity.OrderStatusPending, createdOrder.Status)
	require.Len(t, createdOrder.Items, 1)
	require.Equal(t, createdProd.ID, createdOrder.Items[0].ProductID)

	// -----------------------------------------------------------------
	// 4️⃣  Cancel the order – the use‑case should set the status to
	//     OrderStatusCancelled and persist the change.
	// -----------------------------------------------------------------
	err = ordUC.Cancel(ctx, createdOrder.ID)
	require.NoError(t, err, "order cancellation must not error")

	// Fetch the order again to verify the new status.
	fetched, err := ordUC.GetByID(ctx, createdOrder.ID)
	require.NoError(t, err, "fetching order after cancel must not error")
	require.Equal(t, entity.OrderStatusCancelled, fetched.Status,
		"order status must be Cancelled after Cancel()")
}
```

### What the test does

| Step | Action | Why it matters for the *full flow* test |
|------|--------|------------------------------------------|
| **1️⃣ Category creation** | Calls the *Category* use‑case `Create`. | Guarantees that a category can be persisted and later referenced by a product. |
| **2️⃣ Product creation** | Calls the *Product* use‑case `Create` with the `CategoryID` from step 1. | Checks that a product can be linked to a category and that the repository correctly enforces the foreign‑key relationship. |
| **3️⃣ Order creation** | Calls the *Order* use‑case `Create` with a line item that points to the product from step 2. | Validates that an order can be built from existing products and that the total price / quantity handling works. |
| **4️⃣ Order cancellation** | Calls the *Order* use‑case `Cancel` and then re‑reads the order. | Ensures the business rule “an order can be cancelled” updates the status and persists it. |

### Why this test fits the existing suite

* **Integration level** – It uses the real SQLite repository (`setupTestDB()` creates an in‑memory DB, runs migrations, and seeds data).  
* **Clean‑architecture boundaries** – The test talks only to the *use‑case* layer; the underlying repositories are injected, so we keep the same separation as the other integration tests.  
* **Deterministic** – All data is created inside the test, so no external state interferes (unlike the flaky `TestIntegrationProductSearch`).  
* **Fast & isolated** – The `defer cleanup()` call drops the in‑memory DB after the test, guaranteeing no cross‑test contamination.  

Add the file, run `go test ./...` and you should see the new test pass alongside the existing 62 tests, bringing the total to **63**. If you prefer to keep the test count tidy, you can delete the file after the CI run and move the logic into a dedicated `full_flow_test.go` file – the important part is that the test exists and validates the end‑to‑end flow.
